import { GoogleGenAI, Type } from "@google/genai";
import { MarketAnalysis, TradingSignal, NewsItem } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY as string });

export const getMarketAnalysis = async (query?: string): Promise<MarketAnalysis> => {
  const model = "gemini-3-flash-preview";

  const systemInstruction = `
    You are a World-Class Senior Financial Analyst and Quantitative Trader specializing in global stock markets and geopolitical impacts (Aranceles, Political Conflicts, Economic Shifts).
    Your task is to analyze current global events (like Trump's tariffs, Venezuela conflicts, Fed decisions) and predict market movements specifically for assets available on Plus500.

    Format the response as JSON.
    Provide specific trading signals including entry points, take profits, and stop losses.
    Always prioritize risk management.
  `;

  const prompt = query || "Provide a comprehensive analysis of the current global market state, focusing on high-impact news like geopolitical tensions and trade wars. Identify 3 high-probability trading opportunities with specific technical levels.";

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          globalSentiment: { type: Type.STRING },
          newsContext: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING },
                title: { type: Type.STRING },
                summary: { type: Type.STRING },
                impact: { type: Type.STRING },
                sentiment: { type: Type.STRING },
                date: { type: Type.STRING }
              }
            }
          },
          topOpportunities: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                asset: { type: Type.STRING },
                action: { type: Type.STRING },
                entryRange: { type: Type.STRING },
                takeProfit: { type: Type.STRING },
                stopLoss: { type: Type.STRING },
                reasoning: { type: Type.STRING },
                confidence: { type: Type.NUMBER }
              }
            }
          }
        },
        required: ["globalSentiment", "newsContext", "topOpportunities"]
      }
    }
  });

  try {
    return JSON.parse(response.text);
  } catch (error) {
    console.error("Failed to parse Gemini response", error);
    throw new Error("Analysis generation failed");
  }
};

