import { GoogleGenAI, Type } from "@google/genai";
import { MarketAnalysis } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY as string });

export const getMarketAnalysis = async (query?: string): Promise<MarketAnalysis> => {
  const model = "gemini-3-flash-preview";

  const systemInstruction = `
    Eres un Analista Financiero Senior y experto en Geopolítica. 
    Tu objetivo es analizar eventos actuales del mundo (aranceles, guerras, conflictos en Venezuela, decisiones de bancos centrales) y traducirlos en oportunidades de inversión para Plus500.

    INSTRUCCIONES CRÍTICAS:
    1. RESPONDE SIEMPRE EN ESPAÑOL.
    2. Utiliza la herramienta de búsqueda para obtener las últimas noticias sobre el tema solicitado.
    3. Para cada señal, define: Activo (de Plus500), Acción (COMPRA/VENTA), Rango de Entrada, Take Profit y Stop Loss.
    4. Explica el razonamiento técnico y geopolítico.
  `;

  const prompt = query || "Analiza los eventos geopolíticos más importantes de hoy, incluyendo tensiones en Sudamérica (Venezuela), política comercial de EE.UU. (Trump/aranceles) y su impacto en el Petróleo, Oro y NASDAQ. Sugiere 3 operaciones claras.";

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
    config: {
      systemInstruction,
      tools: [{ googleSearch: {} }],
      // Nota: No usamos responseSchema aquí porque googleSearch puede devolver contenido no estructurado 
      // que preferimos procesar manualmente o dejar que la IA formatee como JSON en texto.
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          globalSentiment: { type: Type.STRING },
          newsContext: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING },
                title: { type: Type.STRING },
                summary: { type: Type.STRING },
                impact: { type: Type.STRING },
                sentiment: { type: Type.STRING },
                date: { type: Type.STRING }
              }
            }
          },
          topOpportunities: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                asset: { type: Type.STRING },
                action: { type: Type.STRING },
                entryRange: { type: Type.STRING },
                takeProfit: { type: Type.STRING },
                stopLoss: { type: Type.STRING },
                reasoning: { type: Type.STRING },
                confidence: { type: Type.NUMBER }
              }
            }
          }
        },
        required: ["globalSentiment", "newsContext", "topOpportunities"]
      }
    }
  });

  try {
    const analysis: MarketAnalysis = JSON.parse(response.text);

    // Extraer fuentes de grounding si existen
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    if (groundingChunks) {
      analysis.sources = groundingChunks
        .filter(chunk => chunk.web)
        .map(chunk => ({
          title: chunk.web.title,
          uri: chunk.web.uri
        }));
    }

    return analysis;
  } catch (error) {
    console.error("Error al procesar respuesta", error);
    throw new Error("No se pudo generar el análisis predictivo.");
  }
};

import React, { useState, useEffect } from 'react';
import { MarketAnalysis, TradingSignal } from './types';
import { getMarketAnalysis } from './services/gemini';
import { MarketChart } from './components/MarketChart';
import { 
  TrendingUp, 
  Globe, 
  ShieldAlert, 
  Zap, 
  RefreshCw, 
  Search,
  MessageSquareText,
  DollarSign,
  ChevronRight,
  PlusCircle,
  Bookmark,
  BookmarkCheck,
  ExternalLink,
  Calendar,
  Clock
} from 'lucide-react';

const App: React.FC = () => {
  const [loading, setLoading] = useState(true);
  const [analysis, setAnalysis] = useState<MarketAnalysis | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [watchlist, setWatchlist] = useState<TradingSignal[]>([]);

  // Cargar Watchlist de LocalStorage
  useEffect(() => {
    const saved = localStorage.getItem('plus_trader_watchlist');
    if (saved) setWatchlist(JSON.parse(saved));
  }, []);

  const fetchAnalysis = async (query?: string) => {
    setLoading(true);
    setError(null);
    try {
      const data = await getMarketAnalysis(query);
      setAnalysis(data);
    } catch (err) {
      setError('Error de conexión con el motor de IA. Inténtalo de nuevo.');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchAnalysis();
  }, []);

  const toggleWatchlist = (signal: TradingSignal) => {
    const isPresent = watchlist.some(s => s.asset === signal.asset && s.timestamp === signal.timestamp);
    let newWatchlist;
    if (isPresent) {
      newWatchlist = watchlist.filter(s => !(s.asset === signal.asset && s.timestamp === signal.timestamp));
    } else {
      newWatchlist = [...watchlist, { ...signal, timestamp: Date.now() }];
    }
    setWatchlist(newWatchlist);
    localStorage.setItem('plus_trader_watchlist', JSON.stringify(newWatchlist));
  };

  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault();
    if (searchQuery.trim()) {
      fetchAnalysis(`Analiza específicamente: ${searchQuery}. Busca noticias de hoy sobre esto.`);
    }
  };

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 selection:bg-blue-500/30 font-sans pb-20">

      {/* Ticker de Mercado */}
      <div className="bg-blue-600/10 border-b border-blue-500/20 py-2 overflow-hidden whitespace-nowrap">
        <div className="flex animate-[marquee_30s_linear_infinite] gap-12 items-center">
          {[
            { n: "ORO", p: "2,045.20", c: "+0.45%" },
            { n: "PETRÓLEO BRENT", p: "82.14", c: "-1.20%" },
            { n: "NASDAQ 100", p: "17,850.40", c: "+0.85%" },
            { n: "EUR/USD", p: "1.0842", c: "-0.15%" },
            { n: "BITCOIN", p: "64,210.00", c: "+2.10%" },
            { n: "S&P 500", p: "5,120.30", c: "+0.30%" },
            { n: "IBEX 35", p: "10,120.00", c: "-0.05%" }
          ].map((m, i) => (
            <div key={i} className="flex gap-2 items-center text-xs font-bold">
              <span className="text-slate-400">{m.n}:</span>
              <span className="text-white">{m.p}</span>
              <span className={m.c.startsWith('+') ? 'text-green-400' : 'text-red-400'}>{m.c}</span>
            </div>
          ))}
        </div>
      </div>

      {/* Navegación */}
      <nav className="border-b border-slate-800 bg-slate-950/80 backdrop-blur-md sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <Zap className="w-6 h-6 text-blue-500" />
